INSERT INTO `about_us` (`id`, `page_name`, `page_type`, `page_content`, `page_url`, `show_in_header`, `show_in_footer`, `require_login`, `created_at`, `updated_at`) VALUES
(1, 'About Us', 'content', '<ol><li><strong>ERP</strong> is a leading platform dedicated to connecting clients with professional trainers for personalized fitness and wellness services. Our mission is to make fitness accessible, convenient, and effective for everyone, whether you prefer online sessions or in-person training.</li><li>We believe that health is a journey, and our platform provides the tools, guidance, and support needed to help you achieve your fitness goals. With ERP, clients can easily browse trainer profiles, book sessions, track progress, and access customized workout plans tailored to their needs.</li><li>Our team of certified trainers is committed to delivering high-quality, safe, and engaging training experiences. Each trainer on ERP is carefully vetted to ensure they meet our rigorous standards of professionalism, expertise, and dedication to client success.</li><li>At ERP, we value innovation and continuously improve our platform to provide cutting-edge fitness solutions. From easy-to-use scheduling tools to insightful progress tracking, our features are designed to enhance the experience for both clients and trainers.</li><li>Beyond fitness, ERP aims to build a vibrant community where clients and trainers can connect, share achievements, and motivate each other. We believe that a supportive environment is key to sustaining long-term health and wellness.</li><li><strong>ERP – Empowering Your Fitness Journey, One Session at a Time.</strong></li></ol>', NULL, 1, 1, 0, '2025-09-12 05:58:26', '2025-10-30 11:18:19');

