(78, 5, 'pt', 'Deal Assigned', '<p style=\"line-height: 28px; font-family: Nunito, &quot;Segoe UI&quot;, arial; font-size: 14px;\"><span style=\"font-family: sans-serif;\">Olá,</span><br style=\"font-family: sans-serif;\"><span style=\"font-family: sans-serif;\">Сделка была перемещена из {deal_old_stage} в&nbsp; {deal_new_stage}.</span></p><p style=\"line-height: 28px; font-family: Nunito, &quot;Segoe UI&quot;, arial; font-size: 14px;\"><span style=\"font-family: sans-serif;\"><span style=\"font-weight: bolder;\">Nome do negócio</span>&nbsp;: {deal_name}<br><span style=\"font-weight: bolder;\">Pipeline de negócios</span>&nbsp;: {deal_pipeline}<br><span style=\"font-weight: bolder;\">Estágio do negócio</span>&nbsp;: {deal_stage}<br><span style=\"font-weight: bolder;\">Status da transação</span>&nbsp;: {deal_status}<br><span style=\"font-weight: bolder;\">Preço da oferta</span>&nbsp;: {deal_price}</span></p><p></p>', '2025-07-14 12:56:09', '2025-07-14 12:56:09'),
